final:
module top_module (
    input t,
    input y,
    output reg not_valid
);
    always @(*) begin
        case ({t, y})
            2'b10: not_valid = 1'b1;
            2'b11: not_valid = 1'b1;
            2'b01: not_valid = 1'b1;
            2'b00: not_valid = 1'b1;
        endcase
    end
endmodule
